SELECT count(1) FROM tb_pmb_plan_list a LEFT JOIN tb_mbm_company_list b ON a.host = b.id
LEFT JOIN tb_pmb_plan_sales_plan_list f ON a.id = f.plan_id
WHERE f.sales_id = #{searchSalesId}

SELECT
FROM tb_pmb_plan_list a LEFT JOIN tb_mbm_company_list b ON a.host = b.id WHERE a.sale_status = 1 AND a.disp_yn = 1 AND a.id IN
#{planid}
#{planid}
ORDER BY FIELD( a.id,
#{planid}
)
ORDER BY FIELD( a.id, #{searchCookieIds}) desc
ORDER BY sale_price

SELECT a.banner_id ,a.plan_id ,b.* ,(select MAX(logo_img) from tb_mbm_company_list WHERE id = b.host) planLogoImg ,(select count(1) from tb_pmb_plan_zzim where prod_id = b.id) planZzimCnt ,(select count(1) from tb_pmb_plan_req_mng where req_prod = b.id) planReqCnt FROM tb_svc_banner_plan_list a LEFT JOIN tb_pmb_plan_list b ON a.plan_id = b.id WHERE a.banner_id = #{searchBannerId}
ORDER BY a.id DESC
LIMIT #{offset}, #{recordSize}
